# Workflow tests: drive the workflow through `act` for each test case, capture
# output into act-result.txt, and assert exact expected values.
#
# The harness copies the project into a fresh temp dir, initializes a git repo,
# swaps in the test case's fixtures as the files the workflow reads, then runs
# `act push --rm`. All output is appended to act-result.txt in the project root.

BeforeDiscovery {
    $script:RepoRoot = Split-Path -Parent $PSScriptRoot
    $script:CaseDir  = Join-Path $PSScriptRoot 'workflow-cases'

    # Two cases, each with its own manifest + license-map. Config is shared.
    # Expected summary values are what the known-good license map produces.
    $script:Cases = @(
        [pscustomobject]@{
            Name     = 'mixed'
            Expected = @{
                total    = 4
                approved = 2
                denied   = 1
                unknown  = 1
                deps     = @{
                    'lodash'   = 'approved'
                    'some-gpl' = 'denied'
                    'mystery'  = 'unknown'
                    'jest'     = 'approved'
                }
            }
        },
        [pscustomobject]@{
            Name     = 'all-approved'
            Expected = @{
                total    = 2
                approved = 2
                denied   = 0
                unknown  = 0
                deps     = @{
                    'lodash'  = 'approved'
                    'express' = 'approved'
                }
            }
        }
    )
}

BeforeAll {
    $script:RepoRoot  = Split-Path -Parent $PSScriptRoot
    $script:CaseDir   = Join-Path $PSScriptRoot 'workflow-cases'
    $script:ResultLog = Join-Path $script:RepoRoot 'act-result.txt'

    # Start with a fresh result log.
    if (Test-Path $script:ResultLog) { Remove-Item $script:ResultLog -Force }
    New-Item -ItemType File -Path $script:ResultLog | Out-Null

    # Run actionlint once up-front — cheap guard against broken YAML.
    $script:WorkflowPath = Join-Path $script:RepoRoot '.github/workflows/dependency-license-checker.yml'
    & actionlint $script:WorkflowPath
    $script:ActionlintExit = $LASTEXITCODE

    # Run act for each case in BeforeAll so we do not exceed the 3-run cap by
    # re-running inside individual `It` blocks.
