# Re-define the exported function inside the module scope so that
# Invoke-LicenseCheck picks it up via the module's own function table.
$mod = Get-Module LicenseChecker
& $mod {
    param($tbl)
    function script:Get-PackageLicense {
        param([string]$Name, [string]$Version)
        if ($tbl.ContainsKey($Name)) { return $tbl[$Name] }
        return 'UNKNOWN'
    }
} $lookup

